SELECT SUM(sum_of_values_added) AS total_sum_of_values_added
FROM sum_of_values_added
WHERE year = 2023;

SELECT industry_id, SUM(value_added) AS total_value_added
FROM value_added
GROUP BY industry_id;

SELECT good_service_name
FROM goods_services
WHERE is_taxable = 1;

SELECT SUM(value_added) AS total_value_added
FROM value_added
WHERE year = 2023;

SELECT sum_of_values_added
FROM sum_of_values_added
WHERE year = 2023;

SELECT SUM(value_added) AS total_value_added
FROM value_added
WHERE industry_id = 0 AND year = 2023;

SELECT SUM(demand) AS total_demand
FROM final_demand
WHERE good_service_id = 1 AND year = 2023;

SELECT good_service_id, demand, industry_id, year
FROM final_demand
WHERE year = 2023;
